import{_ as e,a as t,b as i,c as n}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as l,o as d,c as r,a2 as s}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Magnet Transfer","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/Other/magnet-transfer.md","filePath":"id-ID/Other/magnet-transfer.md","lastUpdated":1781962217000}'),o={name:"id-ID/Other/magnet-transfer.md"};function u(k,a,m,p,h,g){return d(),r("div",null,[...a[0]||(a[0]=[s('<h1 id="magnet-transfer" tabindex="-1">Magnet Transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet Transfer&quot;">​</a></h1><p>Magnet transfer mengunduh file dari magnet link, lalu otomatis menguploadnya ke cloud storage channel yang Anda pilih.</p><p>Fitur ini berguna untuk memindahkan episode anime, video, arsip, dan file sejenis. Tempelkan magnet link, lalu ImgBed membuat background download task. Setelah download selesai, file akan diupload ke ImgBed dan link akhir muncul di daftar upload.</p><p><img src="'+e+'" alt="Magnet transfer" loading="lazy"></p><h2 id="lokasi-pemakaian" tabindex="-1">Lokasi Pemakaian <a class="header-anchor" href="#lokasi-pemakaian" aria-label="Permalink to &quot;Lokasi Pemakaian&quot;">​</a></h2><p>Entry magnet transfer ada di area upload homepage.</p><p>Tempelkan magnet link ke kotak input, pilih <code>Transfer</code>, lalu upload.</p><p><img src="'+t+'" alt="Upload anime" loading="lazy"></p><h2 id="sebelum-pertama-kali-dipakai" tabindex="-1">Sebelum Pertama Kali Dipakai <a class="header-anchor" href="#sebelum-pertama-kali-dipakai" aria-label="Permalink to &quot;Sebelum Pertama Kali Dipakai&quot;">​</a></h2><p>Konfigurasikan magnet transfer di panel admin terlebih dahulu.</p><p>Biasanya Anda membutuhkan:</p><ol><li>Akun GitHub untuk menjalankan download task.</li><li>Cloud upload channel, misalnya Google Drive atau OneDrive.</li><li>Direktori upload tujuan.</li><li>Task timeout.</li></ol><p>Setelah pengaturan siap, kembali ke homepage dan tempelkan magnet link untuk mulai transfer.</p><h2 id="mengupload-magnet-link" tabindex="-1">Mengupload Magnet Link <a class="header-anchor" href="#mengupload-magnet-link" aria-label="Permalink to &quot;Mengupload Magnet Link&quot;">​</a></h2><ol><li>Tempelkan magnet link ke kotak upload di homepage.</li><li>Pastikan mode sudah diatur ke <code>Transfer</code>.</li><li>Klik upload.</li><li>Tunggu ImgBed membuat magnet task.</li><li>Setelah task dimulai, gunakan panel mengambang <code>Magnet Tasks</code> di kanan bawah untuk memeriksa progress.</li></ol><p>Download dan upload bisa memakan waktu. Kecepatan bergantung pada resource magnet, runtime GitHub, dan cloud storage channel yang dipilih.</p><p><img src="'+i+'" alt="Magnet downloading" loading="lazy"></p><h2 id="setelah-selesai" tabindex="-1">Setelah Selesai <a class="header-anchor" href="#setelah-selesai" aria-label="Permalink to &quot;Setelah Selesai&quot;">​</a></h2><p>Setelah task selesai, daftar upload menampilkan nama file dan link.</p><p>Video menampilkan preview video, gambar menampilkan preview gambar, dan file lain menampilkan ikon file biasa.</p><p><img src="'+n+'" alt="Downloaded video" loading="lazy"></p><p>Anda bisa menyalin:</p><table tabindex="0"><thead><tr><th>Jenis Link</th><th>Kegunaan</th></tr></thead><tbody><tr><td>Original link</td><td>Akses file langsung</td></tr><tr><td>Markdown</td><td>Post Markdown atau catatan</td></tr><tr><td>HTML</td><td>Kode halaman web</td></tr><tr><td>BBCode</td><td>Forum yang mendukung BBCode</td></tr></tbody></table><h2 id="panel-magnet-task" tabindex="-1">Panel Magnet Task <a class="header-anchor" href="#panel-magnet-task" aria-label="Permalink to &quot;Panel Magnet Task&quot;">​</a></h2><p>Panel magnet task di kanan bawah menampilkan jumlah task, nama task, progress, dan status akhir.</p><p>Status umum:</p><table tabindex="0"><thead><tr><th>Status</th><th>Arti</th></tr></thead><tbody><tr><td>Waiting</td><td>Task sudah dibuat dan menunggu dijalankan.</td></tr><tr><td>Downloading</td><td>Resource magnet sedang diunduh.</td></tr><tr><td>Uploading</td><td>File sudah selesai diunduh dan sedang diupload ke cloud storage.</td></tr><tr><td>Completed</td><td>Upload berhasil dan link bisa disalin.</td></tr><tr><td>Failed</td><td>Task tidak selesai dengan sukses. Periksa pesan yang muncul, lalu coba lagi.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Jika satu magnet link berisi beberapa file, ImgBed memprioritaskan file utama yang sudah selesai untuk ditampilkan.</li><li>File besar membutuhkan waktu lebih lama. Tunggu task selesai sebelum refresh halaman.</li><li>Jika resource magnet tidak memiliki peer yang tersedia, proses bisa sangat lambat atau gagal.</li><li>Jika kuota cloud account habis, authorization kedaluwarsa, atau direktori upload salah, task bisa gagal.</li><li>Preview video mungkin butuh beberapa detik setelah upload selesai.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="tidak-ada-yang-berjalan-setelah-magnet-link-ditempel" tabindex="-1">Tidak Ada yang Berjalan Setelah Magnet Link Ditempel <a class="header-anchor" href="#tidak-ada-yang-berjalan-setelah-magnet-link-ditempel" aria-label="Permalink to &quot;Tidak Ada yang Berjalan Setelah Magnet Link Ditempel&quot;">​</a></h3><p>Pastikan magnet transfer sudah diaktifkan di panel admin, dan akun GitHub serta cloud channel yang dapat dipakai sudah dipilih.</p><h3 id="download-selalu-lambat" tabindex="-1">Download Selalu Lambat <a class="header-anchor" href="#download-selalu-lambat" aria-label="Permalink to &quot;Download Selalu Lambat&quot;">​</a></h3><p>Kecepatan magnet bergantung pada resource itu sendiri. Jika tidak ada peer yang tersedia, download bisa sangat lambat atau tidak mungkin dilakukan.</p><h3 id="preview-tidak-muncul-setelah-upload" tabindex="-1">Preview Tidak Muncul Setelah Upload <a class="header-anchor" href="#preview-tidak-muncul-setelah-upload" aria-label="Permalink to &quot;Preview Tidak Muncul Setelah Upload&quot;">​</a></h3><p>Pastikan link file bisa dibuka. Untuk file video, browser mungkin butuh waktu singkat untuk memuatnya, atau Anda bisa membuka link secara langsung.</p><h3 id="apa-yang-perlu-dicek-jika-task-gagal" tabindex="-1">Apa yang Perlu Dicek Jika Task Gagal? <a class="header-anchor" href="#apa-yang-perlu-dicek-jika-task-gagal" aria-label="Permalink to &quot;Apa yang Perlu Dicek Jika Task Gagal?&quot;">​</a></h3><p>Periksa apakah magnet link valid, cloud channel berjalan normal, dan direktori upload sudah benar. Setelah itu kirim task lagi.</p>',38)])])}const P=l(o,[["render",u]]);export{f as __pageData,P as default};
